// // This register captures the input data 'd' on the falling edge of the clock signal 'clk' if the disable signal 'dis' is low. If the reset signal 'rst' is active low, the register should reset to 0 on the falling edge of the clock.
module sync_reset_register(
	input clk,
	input rst,
	input en,
	input [7:0]d,
	output reg [7:0]q
);

	always @(posedge clk) begin
		if (rst)
			q <= 8'd0;
		else if (en)
			q <= d;
	end

endmodule
